  const outfitRule = outfitImagePart ? `
    OUTFIT: Use textures and style from OUTFIT_REFERENCE. Casual/daily fashion: "${outfitDescription}".
    REMINDER: ONLY use the clothes from OUTFIT_REFERENCE, COMPLETELY IGNORE the face and identity of the person shown in that reference image.
  ` : "";

  const backgroundRule = backgroundReferencePart 
    ? `ENVIRONMENT: Use the exact background setting, layout, and atmosphere from the BACKGROUND_REFERENCE image.`
    : `ENVIRONMENT: Set the scene in a natural ${backgroundNote || 'daily lifestyle setting'}.`;

  const poseInstruction = poseLabel ? `CHARACTER POSE (MANDATORY): The person is ${poseLabel}. Ensure the interaction with the product matches this pose perfectly.` : "";

  const sceneInstruction = `SCENE: Context: "${scriptPart}". Action should feel spontaneous and unposed. ${poseInstruction}`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${characterFidelityRule}
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${sceneInstruction} 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });

  if (!isNoProductRequested) {
    referenceImageParts.forEach(part => contents.push({ inlineData: part }));
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - Nhân vật đang cầm trên tay sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".
      - [QUAN TRỌNG: sản phẩm là một vật thể cứng, rắn chắc. KHÔNG ĐƯỢC BIẾN DẠNG, KHÔNG ĐƯỢC LÀM BIẾN DẠNG, KHÔNG ĐƯỢC TẠO HOẠT HÌNH CHO THIẾT BỊ. Giữ cho các cạnh sắc nét và tĩnh hoàn hảo. Duy trì tỷ lệ hình học 1:1 với hình ảnh tham khảo].
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết để tạo video AI (VEO-3) dài 8 giây cho video KOC Review.
  PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.
  !!! CRITICAL IDENTITY RULE !!!: Maintain 100% facial and appearance consistency with the face provided in the reference image (0. Ảnh mặt mẫu). EXCLUDE any facial features or identity from background outfit shots or product images.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO (BẮT BUỘC NHẤT QUÁN). Mô tả chính xác nhân vật trong ảnh tham chiếu: ${voiceDetail}. ${is3D ? "Phong cách hoạt hình 3D Pixar/Disney." : "Phong cách người thật chân thực."}
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Mô tả chính xác không gian bối cảnh trong ảnh tham chiếu. ${is3D ? "Môi trường 3D sống động." : "Ánh sáng điện ảnh chân thực."}
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16). Chuyển động chuyên nghiệp (pan, zoom, dolly) slow vào nhân vật hoặc sản phẩm. tuyệt đối không thay đổi bối cảnh và nhân vật trong suốt 8s.
  PHẦN 5: LỜI THOẠI (DÙNG CHO ĐỒNG BỘ): ✨ Model speaks in ${voiceDetail} characteristics (${voiceGender}): "${scriptText}"
  PHẦN 6: CHẤT LƯỢNG KỸ THUẬT: 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}, Không có nhạc nền, Tuyệt đối không hiệu ứng chuyển cảnh hay lật trang trong suốt 8s.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  }
  if (generatedImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    console.error("Video prompt generation error", error);
    return "Error generating video prompt.";
  }
};

