      <div className="p-3 border-t border-slate-100 bg-white flex gap-2">
        <button
          onClick={onRegenerate}
          disabled={imageData.loading}
          className={`flex-1 py-2 px-2 rounded-lg text-xs font-bold transition-all border border-slate-200 text-slate-600 hover:bg-slate-50 ${
            imageData.loading ? 'opacity-50 cursor-not-allowed' : ''
          }`}
        >
          {imageData.url ? "Tạo lại AI" : "Tạo ảnh AI"}
        </button>

        <button
          onClick={onGeneratePrompt}
          disabled={!imageData.url || videoPrompt.loading || imageData.loading}
          className={`flex-1 py-2 px-2 rounded-lg text-xs font-bold transition-all ${
            !imageData.url || imageData.loading
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
              : videoPrompt.loading
                ? 'bg-orange-100 text-orange-700 cursor-wait'
                : 'bg-slate-900 hover:bg-black text-white shadow-md'
          }`}
        >
          {videoPrompt.loading ? 'Writing...' : 'Video Prompt'}
        </button>
      </div>

      {/* Video Prompt Result Overlay */}
      {videoPrompt.visible && (
        <div className="p-3 bg-slate-900 border-t border-slate-800">
           <div className="flex justify-between items-center mb-2">
             <h4 className="text-orange-500 text-[10px] uppercase font-bold tracking-wider">VEO-3 Prompt</h4>
             <div className="flex gap-2">
               <button 
                 onClick={onTranslate}
                 disabled={videoPrompt.translating}
                 className="text-[10px] text-orange-300 hover:text-orange-200"
               >
                 {videoPrompt.translating ? '...' : 'Dịch'}
               </button>
               <button 
                 onClick={() => navigator.clipboard.writeText(videoPrompt.text)}
                 className="text-[10px] text-slate-400 hover:text-white"
               >
                 Copy
               </button>
             </div>
           </div>
           <textarea 
             readOnly 
             className="w-full h-24 bg-slate-950 text-slate-300 text-[10px] p-2 rounded border border-slate-800 focus:outline-none resize-none font-mono"
             value={videoPrompt.text}
           />
        </div>
      )}
    </div>
  );
};

