interface ImageCardProps {
  label: string;
  imageData: GeneratedImage;
  videoPrompt: VideoPromptState;
  onGeneratePrompt: () => void;
  onRegenerate: () => void;
  onTranslate: () => void;
  onUpload?: (file: File) => void;
  onDelete?: () => void;
  customPrompt: string;
  onCustomPromptChange: (text: string) => void;
  onPoseChange?: (pose: string) => void;
  pose?: string;
  onAngleChange?: (angle: string) => void;
  angle?: string;
}

const ImageCard: React.FC<ImageCardProps> = ({ 
  label, 
  imageData, 
  videoPrompt, 
  onGeneratePrompt, 
  onRegenerate, 
  onTranslate,
  onUpload,
  onDelete,
  customPrompt,
  onCustomPromptChange,
  onPoseChange,
  pose,
  onAngleChange,
  angle
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && onUpload) {
      onUpload(e.target.files[0]);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="flex flex-col bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden relative">
      {/* Header */}
      <div className="px-4 py-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
        <span className="font-semibold text-sm text-slate-700">{label} Visual</span>
        {imageData.loading && <span className="text-xs text-orange-600 animate-pulse">Generating...</span>}
      </div>

      {/* Image Display Area */}
      <div className="aspect-[9/16] relative bg-slate-100 w-full group">
        {imageData.url ? (
          <>
            <img 
              src={imageData.url} 
              alt={`${label} generated`} 
              className="w-full h-full object-cover"
            />
            {onDelete && (
              <button 
                onClick={onDelete}
                className="absolute top-2 right-2 w-8 h-8 bg-red-600 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-red-700 transition-all z-10"
                title="Xóa hình ảnh"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            )}
          </>
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center">
            {imageData.loading ? (
              <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-2"></div>
            ) : imageData.error ? (
              <div className="flex flex-col items-center gap-2">
                 <span className="text-red-500 text-xs">{imageData.error}</span>
                 <button onClick={onRegenerate} className="px-4 py-2 bg-orange-600 text-white rounded-lg text-xs font-bold shadow-md">Thử lại</button>
              </div>
            ) : (
              <div className="flex flex-col items-center gap-4">
                <span className="text-slate-400 text-[10px] uppercase font-bold tracking-widest px-4">Kịch bản đã sẵn sàng</span>

                <button 
                    onClick={onRegenerate} 
                    className="w-48 py-3 bg-[#f3591a] hover:bg-orange-700 text-white rounded-xl text-xs font-black shadow-lg shadow-orange-100 transition-all active:scale-95 flex items-center justify-center gap-2 uppercase"
                >
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" /></svg>
                    TẠO ẢNH AI
                </button>

                <button 
                    onClick={() => fileInputRef.current?.click()} 
                    className="w-48 py-3 bg-[#e8edf2] hover:bg-slate-200 text-slate-700 rounded-xl text-xs font-black shadow-md transition-all active:scale-95 flex items-center justify-center gap-2 uppercase"
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                    TẢI ẢNH LÊN
                </button>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" />
              </div>
            )}
          </div>
        )}
      </div>

      {/* Select Pose, Angle & Custom Prompt Input */}
      <div className="px-3 py-2 bg-slate-50 border-t border-slate-100 space-y-2">
        {onPoseChange && (
          <select 
            value={pose || ""} 
            onChange={(e) => onPoseChange(e.target.value)}
            className="w-full text-[10px] font-bold p-2 rounded border border-slate-300 focus:border-orange-500 focus:ring-1 focus:ring-orange-200 outline-none bg-white text-slate-600 uppercase shadow-sm"
          >
            {KOC_POSES.map(p => (
              <option key={p.value} value={p.value}>{p.label}</option>
            ))}
          </select>
        )}

        {onAngleChange && (
          <select 
            value={angle || ""} 
            onChange={(e) => onAngleChange(e.target.value)}
            className={`w-full text-[10px] font-black p-2 rounded border outline-none transition-all shadow-sm uppercase ${
              angle 
              ? 'bg-blue-600 text-white border-blue-700' 
              : 'bg-white text-slate-500 border-slate-300'
            }`}
          >
            {CAMERA_ANGLES.map(opt => (
              <option 
                key={opt.value} 
                value={opt.value} 
                className="bg-white text-slate-700 font-bold"
              >
                {opt.label}
              </option>
            ))}
          </select>
        )}

        <textarea
          value={customPrompt || ''}
          onChange={(e) => onCustomPromptChange(e.target.value)}
          placeholder="Ghi chú thêm (VD: bối cảnh quán cafe, xóa sản phẩm...)"
          className="w-full text-xs p-2 rounded border border-slate-300 focus:border-orange-500 focus:ring-1 focus:ring-orange-200 outline-none resize-none bg-white placeholder:text-slate-400 font-medium"
          rows={2}
        />
      </div>

      {/* Action Footer */}
      <div className="p-3 border-t border-slate-100 bg-white flex gap-2">
        <button
          onClick={onRegenerate}
          disabled={imageData.loading}
          className={`flex-1 py-2 px-2 rounded-lg text-xs font-bold transition-all border border-slate-200 text-slate-600 hover:bg-slate-50 ${
            imageData.loading ? 'opacity-50 cursor-not-allowed' : ''
          }`}
        >
          {imageData.url ? "Tạo lại AI" : "Tạo ảnh AI"}
        </button>

        <button
          onClick={onGeneratePrompt}
          disabled={!imageData.url || videoPrompt.loading || imageData.loading}
          className={`flex-1 py-2 px-2 rounded-lg text-xs font-bold transition-all ${
            !imageData.url || imageData.loading
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
              : videoPrompt.loading
                ? 'bg-orange-100 text-orange-700 cursor-wait'
                : 'bg-slate-900 hover:bg-black text-white shadow-md'
          }`}
        >
          {videoPrompt.loading ? 'Writing...' : 'Video Prompt'}
        </button>
      </div>

      {/* Video Prompt Result Overlay */}
      {videoPrompt.visible && (
        <div className="p-3 bg-slate-900 border-t border-slate-800">
           <div className="flex justify-between items-center mb-2">
             <h4 className="text-orange-500 text-[10px] uppercase font-bold tracking-wider">VEO-3 Prompt</h4>
             <div className="flex gap-2">
               <button 
                 onClick={onTranslate}
                 disabled={videoPrompt.translating}
                 className="text-[10px] text-orange-300 hover:text-orange-200"
               >
                 {videoPrompt.translating ? '...' : 'Dịch'}
               </button>
               <button 
                 onClick={() => navigator.clipboard.writeText(videoPrompt.text)}
                 className="text-[10px] text-slate-400 hover:text-white"
               >
                 Copy
               </button>
             </div>
           </div>
           <textarea 
             readOnly 
             className="w-full h-24 bg-slate-950 text-slate-300 text-[10px] p-2 rounded border border-slate-800 focus:outline-none resize-none font-mono"
             value={videoPrompt.text}
           />
        </div>
      )}
    </div>
  );
};

