const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Xử lý ảnh trang phục: Xóa nhân vật và bối cảnh, trả về ảnh trang phục trên nền trắng.
 */
export const extractOutfitImage = async (outfitPart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Generate a professional product photography image of ONLY the clothing shown in the reference image. 
    1. REMOVE the person/character completely.
    2. REMOVE the background completely.
    3. The clothing must be displayed alone on a clean, solid pure white background (#FFFFFF). 
    4. Preserve the exact patterns, colors, and textures of the clothes 100%.
    5. Arrange the clothes naturally as if on an invisible mannequin or a clean flat lay.
    6. Ensure the result is a high-quality, sharp image of just the garments.
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: prompt }, { inlineData: outfitPart }] }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { 
    console.error("Extract outfit image error:", error);
    throw error; 
  }
};

