export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  addressing: string, sceneCount: number, targetAudience: string = ""
): Promise<ScriptParts> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const prompt = `Trong vai 1 Creator viral hãy tạo kịch bản bán hàng cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". Nhân vật ${gender}, ${voiceDetail}. Xưng hô "${addressing}". Mỗi phần v1..v${sceneCount} dài 160-190 ký tự. Không dùng từ cấm: ${FORBIDDEN_TERMS}`;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties, required } }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) { return {}; }
};

export const regenerateKocScriptPart = async (
  imageParts: any[], productName: string, keyword: string, scriptPartKey: string,
  currentPartContent: string, fullScript: ScriptParts, gender: string, voice: string,
  addressing: string, layout: string, targetAudience: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `Viết lại phần "${scriptPartKey}" cho "${productName}". Dài 160-190 ký tự. Xưng hô "${addressing}". ${getVoiceDetailedInstruction(voice)}.`;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim() || currentPartContent;
  } catch (error) { return currentPartContent; }
};

/**
 * Tạo hình ảnh với TUÂN THỦ TUYỆT ĐỐI GHI CHÚ NHÂN VẬT & SẢN PHẨM & TRANG PHỤC & BỐI CẢNH.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null,
  cameraAngle: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar style, vibrant colors, expressive, polished CGI.`
    : `Photorealistic RAW PHOTO, 8k, cinematic natural lighting, authentic textures.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "no product", "remove product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  // !!! MASTER IDENTITY RULES !!!
  const identityRule = faceImagePart 
    ? `!!! ABSOLUTE FACE IDENTITY: Use EXACT facial features from FACE_REFERENCE. 1:1 Match.`
    : `IDENTITY: Adult Vietnamese ${gender}. ${characterDescription}`;

  const outfitRule = outfitImagePart ? `OUTFIT: Wear the EXACT garments from OUTFIT_REFERENCE.` : "";

  // !!! THE REVOLUTIONARY BACKGROUND LOCK !!!
  const backgroundRule = backgroundReferencePart 
    ? `!!! MANDATORY PHYSICAL SET LOCK (STRICT) !!!:
       1. SETTING: This photo is taken inside the EXACT SAME ROOM shown in the BACKGROUND_REFERENCE image.
       2. ARCHITECTURE LOCK: Walls, floor, ceiling, windows, and fixed furniture MUST remain identical to the reference.
       3. PROPS LOCK: Every object, plant, or decorative item from BACKGROUND_REFERENCE must be in the same position.
       4. PERSPECTIVE SHIFT: The camera is now positioned at technical angle: "${cameraAngle || 'front view'}".
       5. Imagine you are a real photographer moving your tripod within this specific room. Do not hallucinate new rooms.`
    : `ENVIRONMENT: Set in ${backgroundNote || 'lifestyle setting'}. Camera angle: ${cameraAngle || 'front view'}.`;

  const visualRules = `
    RULES: No text, no letters, no UI. Medium Shot.
    PRODUCT SCALE: Product "${productName}" must be 1:1 scale relative to character. Fixed size across scenes.
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${visualRules}
    ${visualNote ? `Visual note: ${visualNote}.` : ""}
    POSE: ${poseLabel}.
    SCENE CONTEXT: "${scriptPart}". 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (!isNoProductRequested) referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

export const generateKocVeoPrompt = async (
  productName: string, scriptText: string, gender: string, voice: string,
  productImageData?: string, generatedImageBase64?: string, isNoProductRequested: boolean = false, imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const prompt = `Nhiệm vụ: Viết prompt chi tiết cho AI Video (VEO-3) 8 giây. Duy trì 100% bối cảnh và nhân vật như ảnh tham chiếu. Style: ${is3D ? "3D Animation" : "Photorealistic"}. Model speaks: "${scriptText}" (${voiceDetail}).`;
  const contents: any[] = [{ text: prompt }];
  if (productImageData) contents.push({ inlineData: { mimeType: 'image/png', data: productImageData.split(',')[1] || productImageData } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  try {
    const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents: { parts: contents } });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (e) { return ""; }
};

