const KocReviewModule: React.FC = () => {
  const storageKey = "koc_project_v23_bg_lock";
  const [state, setState] = useState<any>({
    faceFile: null,
    facePreviewUrl: null,
    outfitFile: null,
    outfitPreviewUrl: null,
    processedOutfitUrl: null,
    isExtractingOutfit: false,
    backgroundFile: null,
    backgroundPreviewUrl: null,
    isGeneratingBG: false,
    characterDescription: '',
    gender: 'Nữ',
    voice: 'Giọng Bắc 20-40 tuổi',
    addressing: '',
    targetAudience: '',
    imageStyle: 'Realistic',
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptTone: '',
    productSize: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const faceInputRef = useRef<HTMLInputElement>(null);
  const outfitInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            productFiles: [],
            faceFile: null,
            outfitFile: null,
            backgroundFile: null,
            isGeneratingScript: false,
            isExtractingOutfit: false,
            isGeneratingBG: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isExtractingOutfit, isGeneratingBG, isRegeneratingPart, productFiles, faceFile, outfitFile, backgroundFile, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: images[key]?.url || '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {}
  }, [state]);

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 3);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({
        ...prev,
        productFiles: updatedFiles,
        productPreviewUrls: updatedUrls
      }));
    }
    if (productInputRef.current) productInputRef.current.value = "";
  };

  const removeProductFile = (idx: number) => {
    const updatedFiles = state.productFiles.filter((_: any, i: number) => i !== idx);
    const updatedPreviewUrls = state.productPreviewUrls.filter((_: any, i: number) => i !== idx);
    setState((prev: any) => ({ ...prev, productFiles: updatedFiles, productPreviewUrls: updatedPreviewUrls }));
  };

  const handleFaceFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({ ...prev, faceFile: file, facePreviewUrl: URL.createObjectURL(file) }));
    }
  };

  const handleOutfitFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({ ...prev, outfitFile: file, outfitPreviewUrl: URL.createObjectURL(file), processedOutfitUrl: null }));
    }
  };

  const handleBackgroundFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({ ...prev, backgroundFile: file, backgroundPreviewUrl: URL.createObjectURL(file) }));
    }
  };

  const handleExtractOutfit = async () => {
    let part = null;
    if (state.outfitFile) part = await service.fileToGenerativePart(state.outfitFile);
    else if (state.outfitPreviewUrl?.startsWith('data:')) part = { mimeType: 'image/png', data: state.outfitPreviewUrl.split(',')[1] };
    if (!part) return;
    setState(p => ({ ...p, isExtractingOutfit: true }));
    try {
      const imgUrl = await service.extractOutfitImage(part);
      setState(p => ({ ...p, processedOutfitUrl: imgUrl, isExtractingOutfit: false }));
    } catch (e) { setState(p => ({ ...p, isExtractingOutfit: false })); }
  };

  const handleGenerateBG = async () => {
    if (!state.scriptNote.trim()) return alert("Vui lòng nhập mô tả bối cảnh để tạo.");
    setState(p => ({ ...p, isGeneratingBG: true }));
    try {
      const imgUrl = await service.generateBaseBackground(state.scriptNote);
      setState(p => ({ ...p, backgroundPreviewUrl: imgUrl, isGeneratingBG: false }));
    } catch (e) { setState(p => ({ ...p, isGeneratingBG: false })); }
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) return alert("Vui lòng tải ảnh sản phẩm.");
    if (!state.productName) return alert("Vui lòng nhập tên sản phẩm.");

    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const initialImages: any = {};
    const initialPrompts: any = {};
    activeKeys.forEach(k => {
      initialImages[k] = { url: '', loading: false, customPrompt: '', pose: '', angle: '' };
      initialPrompts[k] = { text: '', loading: false, visible: false };
    });

    setState((prev: any) => ({ ...prev, isGeneratingScript: true, script: null, images: initialImages, videoPrompts: initialPrompts }));

    try {
      let imageParts = [];
      if (state.productFiles.length > 0) imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      else imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      let layoutToUse = state.scriptLayout || LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateKocScript(
        imageParts, state.productName, state.keyword, state.scriptTone, state.productSize, state.scriptNote, layoutToUse, state.gender, state.voice, state.addressing, state.sceneCount, state.targetAudience
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse }));
    } catch (e) { } finally { setState((prev: any) => ({ ...prev, isGeneratingScript: false })); }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = [];
      if (state.productFiles.length > 0) productParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      else productParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      const getPart = async (file: File | null, url: string | null) => {
        if (file) return await service.fileToGenerativePart(file);
        if (url?.startsWith('data:')) return { mimeType: 'image/png', data: url.split(',')[1] };
        return null;
      };

      const facePart = await getPart(state.faceFile, state.facePreviewUrl);
      const outfitPart = state.processedOutfitUrl ? { mimeType: 'image/png', data: state.processedOutfitUrl.split(',')[1] } : await getPart(state.outfitFile, state.outfitPreviewUrl);
      const bgRefPart = await getPart(state.backgroundFile, state.backgroundPreviewUrl);

      const poseLabel = KOC_POSES.find(p => p.value === state.images[key]?.pose)?.label || "";
      const currentAngleValue = state.images[key]?.angle || "";

      const url = await service.generateKocImage(
        productParts, facePart, outfitPart, "", state.productName, state.script[key], state.characterDescription, state.images[key]?.customPrompt, state.gender, state.imageStyle, state.scriptNote, state.visualNote, poseLabel, bgRefPart, currentAngleValue
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = "";
      if (state.productFiles.length > 0) productImageData = (await service.fileToGenerativePart(state.productFiles[0])).data;
      else if (state.productPreviewUrls.length > 0) productImageData = state.productPreviewUrls[0].split(',')[1];
      const customPrompt = state.images[key]?.customPrompt || "";
      const isNoProduct = ["không có sản phẩm", "xóa sản phẩm"].some(kw => customPrompt.toLowerCase().includes(kw));
      const prompt = await service.generateKocVeoPrompt(state.productName, state.script[key], state.gender, state.voice, productImageData, state.images[key].url, isNoProduct, state.imageStyle);
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) { setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } })); }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
