  const identityRule = faceImagePart 
    ? `!!! ABSOLUTE FACE IDENTITY RULE (MANDATORY) !!!:
       1. YOU MUST USE EXACTLY the facial features, hair color/style, expression, and bone structure from the provided FACE REFERENCE image.
