                <div onClick={() => outfitInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden group">
                  {state.outfitPreviewUrl ? (
                    <>
                      <img src={state.outfitPreviewUrl} className="h-full object-cover" />
                      <button 
