const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Bước 2: Tạo bối cảnh Master (Trống, không người, không sản phẩm) để làm tham chiếu cố định (Physical Set)
 */
export const generateBaseBackground = async (backgroundNote: string): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Generate a professional high-end interior/architectural photography of an EMPTY environment: "${backgroundNote}".
    1. ABSOLUTELY NO PEOPLE, NO CHARACTERS.
    2. ABSOLUTELY NO PRODUCTS, NO LOGOS, NO TEXT.
    3. Wide angle shot showing the room's layout, furniture, and architecture clearly.
    4. High-end cinematic lighting, 8k resolution, photorealistic textures.
    5. This image will be used as a fixed movie set. Ensure all elements are distinct and stable.
    6. Aspect ratio 9:16.
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { 
    console.error("Generate base background error:", error);
    throw error; 
  }
};

/**
 * Xử lý ảnh trang phục: Xóa nhân vật và bối cảnh, trả về ảnh trang phục trên nền trắng.
