export const extractOutfitImage = async (outfitPart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Generate a professional product photography image of ONLY the clothing shown in the reference image. 
    1. REMOVE the person/character completely.
    2. REMOVE the background completely.
    3. The clothing must be displayed alone on a clean, solid pure white background (#FFFFFF). 
    4. Preserve the exact patterns, colors, and textures of the clothes 100%.
    5. Arrange the clothes naturally as if on an invisible mannequin or a clean flat lay.
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: prompt }, { inlineData: outfitPart }] }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

const FORBIDDEN_TERMS = `Facebook, Shopee, Lazada, Tiki, Zalo, QR, Chuyển khoản, Fanpage, Địa Chỉ, Số điện thoại, Có 1 không 2, Em đang có, Xem này, Mã giảm sâu, Voucher, Tiktok, dành riêng, ưu đãi, quà tặng, duy nhất, triân, nhé, nha, thế chứ.`;

const getVoiceDetailedInstruction = (voiceLabel: string) => {
  const mapping: Record<string, string> = {
    "Giọng Bắc 20-40 tuổi": "20-40 tuổi, miền Bắc, năng động, nhịp độ nhanh, vui vẻ, tông cao.",
    "Giọng Nam 20-40 tuổi": "20-40 tuổi, miền Nam, năng động, nhịp độ nhanh, vui vẻ, tông cao.",
    "Giọng Bắc 50-60 tuổi": "50-60 tuổi, miền Bắc, giọng trầm, vang, uy quyền.",
    "Giọng Nam 50-60 tuổi": "50-60 tuổi, miền Nam, giọng trầm, vang, uy quyền.",
    "Giọng Bắc 60-80 tuổi": "60-80 tuổi, miền Bắc, khàn, hào sảng, chân chất.",
    "Giọng Nam 60-80 tuổi": "60-80 tuổi, miền Nam, khàn, hào sảng, chân chất."
  };
  return mapping[voiceLabel] || voiceLabel;
};

export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  addressing: string, sceneCount: number, targetAudience: string = ""
): Promise<ScriptParts> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const prompt = `Trong vai 1 Creator viral tạo kịch bản TikTok cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". Khách hàng: "${targetAudience}". Nhân vật ${gender}, ${voiceDetail}. Xưng hô "${addressing}". Mỗi phần v1..v${sceneCount} dài 160-190 ký tự. Không dùng từ cấm: ${FORBIDDEN_TERMS}`;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties, required } }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) { return {}; }
};

export const regenerateKocScriptPart = async (
  imageParts: any[], productName: string, keyword: string, scriptPartKey: string,
  currentPartContent: string, fullScript: ScriptParts, gender: string, voice: string,
  addressing: string, layout: string, targetAudience: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `Viết lại phần kịch bản "${scriptPartKey}" cho "${productName}". Độ dài 160-190 ký tự. Xưng hô "${addressing}". ${getVoiceDetailedInstruction(voice)}.`;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim() || currentPartContent;
  } catch (error) { return currentPartContent; }
};

/**
 * Bước 3 & 4: Tạo hình ảnh với QUY TRÌNH KHÓA TRƯỜNG QUAY (Master Background) & REAL SKIN TEXTURE.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null,
  cameraAngle: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic soft natural lighting.";

  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar/Disney style, ${lifestyleStyle} vibe, vibrant but natural colors, expressive character, polished CGI.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k resolution, cinematic but realistic natural lighting.`;

  // !!! CRITICAL SKIN REALISM BLOCK !!!
  const skinRealism = is3D ? "" : `
    !!! CRITICAL SKIN REALISM (STRICT MANDATORY) !!!: 
    - Preserving highly detailed human skin texture: visible pores, natural skin micro-lines, and authentic skin blemishes.
    - ABSOLUTELY NO over-smoothing, NO artificial blurring, and NO "plastic" or "doll-like" skin look.
    - Skin must show natural light scattering and subsurface scattering for extreme realism.
  `;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "no product", "remove product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  // !!! MASTER IDENTITY RULES !!!
  const identityRule = faceImagePart 
    ? `!!! ABSOLUTE FACE IDENTITY RULE: Use EXACT facial features from the provided FACE REFERENCE image. 1:1 match.`
    : `IDENTITY: Adult Vietnamese ${gender}. ${characterDescription}`;

  // !!! ABSOLUTE OUTFIT FIDELITY RULE !!!
  const outfitRule = outfitImagePart ? `!!! ABSOLUTE OUTFIT FIDELITY: Character MUST wear the EXACT garments shown in the OUTFIT_REFERENCE image.` : "";

  // !!! MASTER BACKGROUND LOCK & CAMERA ROTATION !!!
  const backgroundRule = backgroundReferencePart 
    ? `!!! ABSOLUTE ENVIRONMENT LOCK (STRICT MANDATORY) !!!:
       1. SETTING: This photo is taken inside the EXACT SAME PHYSICAL ROOM shown in the BACKGROUND_REFERENCE image.
       2. ARCHITECTURE LOCK: Walls, floor, ceiling, doors, windows, and all furniture MUST stay in their same positions as shown in the reference.
       3. NO HALLUCINATION: Do not add or invent new rooms. Maintain 1:1 consistency of the architecture.
       4. PERSPECTIVE SHIFT: Imagine you are a photographer moving your tripod within this specific locked room. Re-orient the camera view to match the technical angle: "${cameraAngle || 'front view'}". 
       5. The room must look like the same physical set used for a movie.`
    : `ENVIRONMENT: Set the scene in a natural ${backgroundNote || 'daily lifestyle setting'}. Camera angle: "${cameraAngle || 'front view'}".`;

  const visualRules = `
    CRITICAL RULES: No text, no logos. Every image MUST be a "Medium Shot".
    PRODUCT SCALE: Product "${productName}" must maintain a fixed, realistic size relative to the character. Proportions must match the product reference image 1:1.
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${skinRealism}
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    POSE: ${poseLabel}.
    SCENE CONTEXT: "${scriptPart}". 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (!isNoProductRequested) referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

export const generateKocVeoPrompt = async (
  productName: string, scriptText: string, gender: string, voice: string,
  productImageData?: string, generatedImageBase64?: string, isNoProductRequested: boolean = false, imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const prompt = `Task: Write prompt for AI Video (VEO-3) 8s. Maintain 100% consistency with reference images for character, outfit, and BACKGROUND. Style: ${is3D ? "3D Animation" : "Photorealistic"}. Model speaks: "${scriptText}" (${voiceDetail}).`;
  const contents: any[] = [{ text: prompt }];
  if (productImageData) contents.push({ inlineData: { mimeType: 'image/png', data: productImageData.split(',')[1] || productImageData } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  try {
    const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents: { parts: contents } });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (e) { return ""; }
};

