  "tui - các bác",
  "tui - mấy ông",
  "mình - cả nhà",
  "mình - mọi người"
];

const KocReviewModule: React.FC = () => {
  const storageKey = "koc_project_v24_bg_fixed_set";
  const [state, setState] = useState<any>({
    faceFile: null,
    facePreviewUrl: null,
    outfitFile: null,
    outfitPreviewUrl: null,
    processedOutfitUrl: null,
    isExtractingOutfit: false,
    backgroundFile: null,
    backgroundPreviewUrl: null,
    isGeneratingBG: false,
    characterDescription: '',
    gender: 'Nữ',
    voice: 'Giọng Bắc 20-40 tuổi',
    addressing: '',
    targetAudience: '',
    imageStyle: 'Realistic',
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptTone: '',
    productSize: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const faceInputRef = useRef<HTMLInputElement>(null);
  const outfitInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            productFiles: [],
            faceFile: null,
            outfitFile: null,
            backgroundFile: null,
            isGeneratingScript: false,
            isExtractingOutfit: false,
            isGeneratingBG: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) {
      console.error("Failed to restore KOC state", e);
    }
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isExtractingOutfit, isGeneratingBG, isRegeneratingPart, productFiles, faceFile, outfitFile, backgroundFile, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: images[key]?.url || '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {
      console.error("Failed to save KOC state", e);
    }
  }, [state]);

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 3);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({
        ...prev,
        productFiles: updatedFiles,
        productPreviewUrls: updatedUrls
      }));
    }
    if (productInputRef.current) productInputRef.current.value = "";
  };

  const removeProductFile = (idx: number) => {
    const updatedFiles = state.productFiles.filter((_: any, i: number) => i !== idx);
    const updatedUrls = updatedFiles.map((f: File) => URL.createObjectURL(f));
    const updatedPreviewUrls = state.productPreviewUrls.filter((_: any, i: number) => i !== idx);
    setState((prev: any) => ({
      ...prev,
      productFiles: updatedFiles,
      productPreviewUrls: updatedFiles.length > 0 ? updatedUrls : updatedPreviewUrls
    }));
  };

  const removeFaceFile = (e: React.MouseEvent) => {
    e.stopPropagation();
    setState((prev: any) => ({ ...prev, faceFile: null, facePreviewUrl: null }));
    if (faceInputRef.current) faceInputRef.current.value = "";
  };

  const removeOutfitFile = (e: React.MouseEvent) => {
    e.stopPropagation();
    setState((prev: any) => ({ ...prev, outfitFile: null, outfitPreviewUrl: null, processedOutfitUrl: null }));
    if (outfitInputRef.current) outfitInputRef.current.value = "";
  };

  const removeBackgroundFile = (e: React.MouseEvent) => {
    e.stopPropagation();
    setState((prev: any) => ({ ...prev, backgroundFile: null, backgroundPreviewUrl: null }));
    if (backgroundInputRef.current) backgroundInputRef.current.value = "";
  };

  const handleFaceFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({ ...prev, faceFile: file, facePreviewUrl: URL.createObjectURL(file) }));
    }
  };

  const handleOutfitFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({ ...prev, outfitFile: file, outfitPreviewUrl: URL.createObjectURL(file), processedOutfitUrl: null }));
    }
  };

  const handleBackgroundFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({ ...prev, backgroundFile: file, backgroundPreviewUrl: URL.createObjectURL(file) }));
    }
  };

  const handleExtractOutfit = async () => {
    let part = null;
    if (state.outfitFile) part = await service.fileToGenerativePart(state.outfitFile);
    else if (state.outfitPreviewUrl?.startsWith('data:')) part = { mimeType: 'image/png', data: state.outfitPreviewUrl.split(',')[1] };
    if (!part) return;
    setState(p => ({ ...p, isExtractingOutfit: true }));
    try {
      const imgUrl = await service.extractOutfitImage(part);
      setState(p => ({ ...p, processedOutfitUrl: imgUrl, isExtractingOutfit: false }));
    } catch (e) { setState(p => ({ ...p, isExtractingOutfit: false })); }
  };

  /**
   * Bước 2: Nhấn nút "Tạo bối cảnh AI"
   */
  const handleGenerateBG = async () => {
    if (!state.scriptNote.trim()) return alert("Vui lòng nhập mô tả bối cảnh để AI có cơ sở vẽ.");
    setState(p => ({ ...p, isGeneratingBG: true }));
    try {
      const imgUrl = await service.generateBaseBackground(state.scriptNote);
      setState(p => ({ ...p, backgroundPreviewUrl: imgUrl, isGeneratingBG: false }));
    } catch (e) { setState(p => ({ ...p, isGeneratingBG: false })); }
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) return alert("Vui lòng tải ảnh sản phẩm.");
    if (!state.productName) return alert("Vui lòng nhập tên sản phẩm.");

    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const initialImages: any = {};
    const initialPrompts: any = {};
    activeKeys.forEach(k => {
      initialImages[k] = { url: '', loading: false, customPrompt: '', pose: '', angle: '' };
      initialPrompts[k] = { text: '', loading: false, visible: false };
    });

    setState((prev: any) => ({ ...prev, isGeneratingScript: true, script: null, images: initialImages, videoPrompts: initialPrompts }));

    try {
      let imageParts = [];
      if (state.productFiles.length > 0) imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      else imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      let layoutToUse = state.scriptLayout || LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateKocScript(
        imageParts, state.productName, state.keyword, state.scriptTone, state.productSize, state.scriptNote, layoutToUse, state.gender, state.voice, state.addressing, state.sceneCount, state.targetAudience
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse }));
    } catch (e) { } finally { setState((prev: any) => ({ ...prev, isGeneratingScript: false })); }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = [];
      if (state.productFiles.length > 0) productParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      else productParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      const getPart = async (file: File | null, url: string | null) => {
        if (file) return await service.fileToGenerativePart(file);
        if (url?.startsWith('data:')) return { mimeType: 'image/png', data: url.split(',')[1] };
        return null;
      };

      const facePart = await getPart(state.faceFile, state.facePreviewUrl);
      const outfitPart = state.processedOutfitUrl ? { mimeType: 'image/png', data: state.processedOutfitUrl.split(',')[1] } : await getPart(state.outfitFile, state.outfitPreviewUrl);

      // Bước 3: Lấy Master Background làm tham chiếu cố định
      const bgRefPart = await getPart(state.backgroundFile, state.backgroundPreviewUrl);

      const poseLabel = KOC_POSES.find(p => p.value === state.images[key]?.pose)?.label || "";
      const currentAngleValue = state.images[key]?.angle || "";

      // Bước 4: Gọi service với yêu cầu skin realism và background lock
      const url = await service.generateKocImage(
        productParts, facePart, outfitPart, "", state.productName, state.script[key], state.characterDescription, state.images[key]?.customPrompt, state.gender, state.imageStyle, state.scriptNote, state.visualNote, poseLabel, bgRefPart, currentAngleValue
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = "";
      if (state.productFiles.length > 0) productImageData = (await service.fileToGenerativePart(state.productFiles[0])).data;
      else if (state.productPreviewUrls.length > 0) productImageData = state.productPreviewUrls[0].split(',')[1];
      const customPrompt = state.images[key]?.customPrompt || "";
      const isNoProduct = ["không có sản phẩm", "xóa sản phẩm"].some(kw => customPrompt.toLowerCase().includes(kw));
      const prompt = await service.generateKocVeoPrompt(state.productName, state.script[key], state.gender, state.voice, productImageData, state.images[key].url, isNoProduct, state.imageStyle);
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) { setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } })); }
  };

  const handleBulkImage = async () => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) {
      await handleGenImageForKey(key);
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("ZIP Lib not loaded");
    const zip = new JSZip();
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    let count = 0;
    for (let i = 0; i < activeKeys.length; i++) {
      const key = activeKeys[i];
      if (state.images[key]?.url) {
        zip.file(`${String(i + 1).padStart(2, '0')}.png`, state.images[key].url.split(',')[1], { base64: true });
        count++;
      }
    }
    if (count === 0) return alert("Không có ảnh để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `koc_images_${Date.now()}.zip`;
    link.click();
  };

  const hasGeneratedItems = state.script && Object.values(state.images).some((img: any) => img.url);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
          {/* CỘT TRÁI: MEDIA INPUT */}
          <div className="md:col-span-5 flex flex-col gap-6">
            <div className="space-y-3">
              <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest">1. Ảnh sản phẩm (Max 3)</label>
              <div onClick={() => productInputRef.current?.click()} className="w-full h-32 rounded-2xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-all group">
                <svg className="w-8 h-8 text-orange-400 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                <span className="text-[10px] font-black uppercase text-slate-400">Tải ảnh sản phẩm</span>
                <input type="file" multiple ref={productInputRef} onChange={handleProductFilesChange} className="hidden" accept="image/*" />
              </div>
              {state.productPreviewUrls.length > 0 && (
                <div className="grid grid-cols-3 gap-3">
                  {state.productPreviewUrls.map((url: string, idx: number) => (
                    <div key={idx} className="relative aspect-[3/4] rounded-xl overflow-hidden border shadow-sm">
                      <img src={url} className="w-full h-full object-cover" />
                      <button onClick={() => removeProductFile(idx)} className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest">0. Mặt mẫu</label>
                <div onClick={() => faceInputRef.current?.click()} className="aspect-square border-2 border-dashed border-slate-300 rounded-2xl flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden group relative">
                  {state.facePreviewUrl ? <><img src={state.facePreviewUrl} className="h-full object-cover" /><button onClick={removeFaceFile} className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button></> : <span className="text-slate-400 font-bold text-[10px]">TẢI MẶT</span>}
                  <input type="file" ref={faceInputRef} onChange={handleFaceFileChange} className="hidden" accept="image/*" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest">2. Trang phục</label>
                <div onClick={() => outfitInputRef.current?.click()} className="aspect-square border-2 border-dashed border-slate-300 rounded-2xl flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden group relative">
                  {state.outfitPreviewUrl ? <><img src={state.outfitPreviewUrl} className="h-full object-cover" /><button onClick={removeOutfitFile} className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button></> : <span className="text-slate-400 font-bold text-[10px]">TRANG PHỤC</span>}
                  <input type="file" ref={outfitInputRef} onChange={handleOutfitFileChange} className="hidden" accept="image/*" />
                </div>
                <button onClick={handleExtractOutfit} disabled={state.isExtractingOutfit} className={`w-full py-2.5 rounded-xl text-[10px] font-black uppercase transition-all shadow-md ${state.processedOutfitUrl ? 'bg-green-100 text-green-700' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
                  {state.isExtractingOutfit ? "..." : state.processedOutfitUrl ? "Đã tách ✓" : "Tách trang phục"}
                </button>
              </div>
            </div>
            <textarea value={state.characterDescription} onChange={e => setState(p => ({ ...p, characterDescription: e.target.value }))} placeholder="Mô tả phong cách nhân vật (VD: Tóc đen dài, phong cách năng động...)" className="w-full p-4 border rounded-2xl h-24 text-sm focus:ring-2 focus:ring-orange-100 outline-none transition-all resize-none" />
          </div>

          {/* CỘT PHẢI: CONFIG & FIXED SET BG */}
          <div className="md:col-span-7 space-y-6">
            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Tên sản phẩm</label><input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Tên sản phẩm..." className="w-full p-3.5 border rounded-2xl focus:ring-2 outline-none font-bold" /></div>
               <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Đối tượng mục tiêu</label><input type="text" value={state.targetAudience} onChange={e => setState(p => ({ ...p, targetAudience: e.target.value }))} placeholder="VD: Mẹ bỉm sữa..." className="w-full p-3.5 border rounded-2xl focus:ring-2 outline-none font-bold" /></div>
            </div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">USP sản phẩm</label><textarea value={state.keyword} onChange={e => setState(p => ({ ...p, keyword: e.target.value }))} placeholder="Các đặc điểm nổi bật..." className="w-full p-3.5 border rounded-2xl h-20 text-sm outline-none resize-none" /></div>

            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Giới tính</label><select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-3.5 border rounded-2xl font-black bg-white appearance-none"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select></div>
               <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Giọng vùng miền</label><select value={state.voice} onChange={e => setState(p => ({ ...p, voice: e.target.value }))} className="w-full p-3.5 border rounded-2xl font-black bg-white appearance-none">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select></div>
            </div>

            <div className="space-y-3">
              <label className="block text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] px-1">1. Trường quay bối cảnh (Physical Environment Set)</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div onClick={() => backgroundInputRef.current?.click()} className="aspect-video border-2 border-dashed border-slate-300 rounded-2xl flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden relative group shadow-inner">
                  {state.backgroundPreviewUrl ? <><img src={state.backgroundPreviewUrl} className="h-full w-full object-cover" /><button onClick={removeBackgroundFile} className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button></> : <div className="text-center opacity-40"><svg className="w-8 h-8 mx-auto text-slate-300 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg><span className="text-[8px] font-black uppercase">Tải hoặc Tạo bối cảnh</span></div>}
                  <input type="file" ref={backgroundInputRef} onChange={handleBackgroundFileChange} className="hidden" accept="image/*" />
                </div>
                <div className="flex flex-col gap-2">
                   <textarea value={state.scriptNote} onChange={e => setState(p => ({ ...p, scriptNote: e.target.value }))} placeholder="Mô tả bối cảnh chi tiết để AI vẽ Master Background (Bước 1)..." className="w-full p-4 border rounded-2xl flex-1 text-sm outline-none resize-none bg-indigo-50/30 focus:bg-white transition-all font-medium" />
                   <button onClick={handleGenerateBG} disabled={state.isGeneratingBG || !state.scriptNote.trim()} className="w-full py-3 bg-indigo-600 text-white text-[10px] font-black rounded-xl hover:bg-indigo-700 transition-all uppercase shadow-lg flex items-center justify-center gap-2">
                     {state.isGeneratingBG ? <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : "✨ Bước 2: Tạo bối cảnh AI"}
                   </button>
                </div>
              </div>
              <p className="text-[9px] font-bold text-slate-400 uppercase italic">* AI sẽ dùng ảnh này làm trường quay cố định cho tất cả các cảnh tiếp theo.</p>
            </div>

            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-5 bg-orange-600 text-white font-black rounded-3xl shadow-2xl hover:bg-orange-700 uppercase tracking-widest transition-all active:scale-[0.98]">
              {state.isGeneratingScript ? "ĐANG XỬ LÝ KỊCH BẢN..." : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl flex justify-between items-center">
            <div>
              <h3 className="text-lg font-black text-white uppercase tracking-tight">KẾT QUẢ CHIẾN DỊCH (Absolute Realism Set)</h3>
              <p className="text-[10px] font-bold text-orange-500 uppercase tracking-widest mt-1 italic">Bối cảnh cố định • Độ chi tiết da cực thực • Style: {state.imageStyle}</p>
            </div>
            <div className="flex gap-3">
              <button onClick={handleBulkImage} className="px-6 py-3 bg-orange-600 text-white text-[10px] font-black rounded-xl hover:scale-105 transition-all uppercase">Tạo tất cả ảnh</button>
              <button onClick={downloadAllImages} className="px-6 py-3 bg-white text-slate-900 text-[10px] font-black rounded-xl hover:bg-slate-200 transition-all uppercase">Tải ZIP</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-8">
            {Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`).map((key, idx) => (
              <div key={key} className="space-y-4 animate-fadeIn">
                <ScriptSection title={`Phần ${idx + 1}`} content={state.script[key]} color="border-orange-500" onChange={(val) => setState(p => ({ ...p, script: { ...p.script, [key]: val } }))} onRegenerate={() => {}} />
                <ImageCard
                  label={`Cảnh ${idx + 1}`} imageData={state.images[key]} videoPrompt={state.videoPrompts[key]} onGeneratePrompt={() => handleGeneratePromptForKey(key)} onRegenerate={() => handleGenImageForKey(key)} onTranslate={() => {}} 
