    "Giọng Nam 50-60 tuổi": "50-60 tuổi, giọng miền Nam, giọng trầm, vang, ổn định, uy quyền, đáng tin cậy, hào hứng. Dùng từ: nha, nè, thiệt, hông.",
    "Giọng Bắc 60-80 tuổi": "60-80 tuổi, giọng miền Bắc, khàn, hào sảng, chân chất, thực tế, hào hứng. Dùng từ: nhé, ạ, thế, chứ.",
    "Giọng Nam 60-80 tuổi": "60-80 tuổi, giọng miền Nam, khàn, hào sảng, chân chất, thực tế, hào hứng. Dùng từ: nha, nè, thiệt, hông."
  };
  return mapping[voiceLabel] || voiceLabel;
};

/**
 * Tạo kịch bản TikTok với NGUYÊN TẮC CỘNG ĐỒNG nghiêm ngặt.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  addressing: string,
  sceneCount: number,
  targetAudience: string = ""
): Promise<ScriptParts> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Trong vai 1 Creator chuyên tạo video viral hãy tạo kịch bản bán hàng cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". 
    ĐỐI TƯỢNG KHÁCH HÀNG MỤC TIÊU: "${targetAudience || 'Mọi người'}". Hãy viết văn phong phù hợp với tệp khách hàng này.
    NHÂN VẬT: Giới tính ${gender}, Đặc điểm giọng nói: ${voiceDetail}.

    YÊU CẦU: Đúng ${sceneCount} phần (v1..v${sceneCount}). KHÔNG nhắc bối cảnh/địa điểm.

    !!! QUAN TRỌNG NHẤT (STRICT LENGTH RULE) !!!:
    Mỗi phần kịch bản (v1, v2...) BẮT BUỘC PHẢI CÓ ĐỘ DÀI TỪ 160 ĐẾN 190 KÝ TỰ. 
    - Tuyệt đối KHÔNG ĐƯỢC NGẮN HƠN 160 ký tự.
    - Tuyệt đối KHÔNG ĐƯỢC DÀI HƠN 190 ký tự.
    - Phần CTA điều hướng khách hàng mua hàng tại giỏ hàng góc trái.
    - Văn phong phải cực kỳ khớp với mô tả giọng nói: ${voiceDetail}.
    - Kịch bản phải bắt đầu bằng một câu hỏi.

    QUY TẮC XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe). 
    Toàn bộ kịch bản phải tuân thủ đúng cặp xưng hô này một cách tự nhiên và xuyên suốt.

    !!! CẢNH BÁO VI PHẠM CỘNG ĐỒNG - TUYỆT ĐỐI KHÔNG SỬ DỤNG CÁC TỪ SAU !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Tạo lại một phần kịch bản cụ thể (v1, v2...)
 */
export const regenerateKocScriptPart = async (
  imageParts: any[], 
  productName: string, 
  keyword: string, 
  scriptPartKey: string,
  currentPartContent: string,
  fullScript: ScriptParts,
  gender: string, 
  voice: string,
  addressing: string,
  layout: string,
  targetAudience: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Hãy VIẾT LẠI phần kịch bản "${scriptPartKey}" cho sản phẩm "${productName}".
    Tệp khách hàng mục tiêu: "${targetAudience}".
    Nội dung cũ: "${currentPartContent}".
    Bối cảnh toàn bộ kịch bản: ${JSON.stringify(fullScript)}.

    YÊU CẦU:
    1. Giữ nguyên phong cách và sự logic với các phần khác.
    2. Độ dài bắt buộc: từ 160 đến 190 ký tự.
    3. Giới tính: ${gender}, Đặc điểm giọng nói: ${voiceDetail}.
    4. XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe).
    5. TUYỆT ĐỐI KHÔNG dùng từ cấm: ${FORBIDDEN_TERMS}
    6. Đảm bảo ngôn từ thu hút và viral hơn bản cũ.

    Trả về duy nhất chuỗi ký tự kịch bản mới.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim() || currentPartContent;
  } catch (error) {
    return currentPartContent;
  }
};

/**
 * Tạo hình ảnh với TUÂN THỦ TUYỆT ĐỐI GHI CHÚ NHÂN VẬT & SẢN PHẨM & TRANG PHỤC.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null,
  cameraAngle: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic soft natural lighting, casual environment.";

  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar/Disney style, ${lifestyleStyle} vibe, vibrant but natural colors, expressive character, polished CGI.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k resolution, authentic skin textures, cinematic but realistic natural lighting.`;

  const skinRealismRule = is3D ? "" : `
    CRITICAL SKIN REALISM: 
    - Preserving highly detailed human skin texture: visible pores, natural skin micro-lines, and authentic skin blemishes.
    - ABSOLUTELY NO over-smoothing, NO artificial blurring, and NO "plastic" or "doll-like" skin look.
    - Skin must show natural light scattering and subsurface scattering for extreme realism.
  `;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  // !!! STRICT FACE EXCLUSIVITY RULES !!!
  const identityRule = faceImagePart 
    ? `!!! ABSOLUTE FACE IDENTITY RULE (MANDATORY) !!!:
       1. YOU MUST USE EXACTLY the facial features, hair color/style, expression, and bone structure from the provided FACE REFERENCE image.
       2. COMPLETELY IGNORE AND EXCLUDE any faces, eyes, or identities found in OUTFIT_REFERENCE or PRODUCT_REFERENCE images.
       3. The character's face MUST come 100% from FACE_REFERENCE only.
       4. The character's face must always be looking directly into the camera.`
    : `IDENTITY: Adult Vietnamese ${gender} matching description: "${characterDescription}".`;

  // !!! ABSOLUTE OUTFIT FIDELITY RULE !!!
  const outfitRule = outfitImagePart ? `
    !!! ABSOLUTE OUTFIT FIDELITY RULE (STRICT MANDATORY) !!!:
    1. The character MUST WEAR the EXACT SAME garments shown in the OUTFIT_REFERENCE image (the one provided on white background).
    2. PRESERVE 100% of the colors, patterns, textures, fabrics, and design of this specific clothing.
    3. DO NOT ALTER, modify, or change the outfit. It must be identical to the reference image in every single scene.
    4. ONLY extract the clothes from this reference; COMPLETELY IGNORE any facial features or person identities that might be present in the original outfit source if it wasn't perfectly cleaned.
    5. Treat this outfit as the character's PERMANENT UNIFORM for this entire collection.
  ` : `OUTFIT: Wear style described as: "${characterDescription}".`;

  const visualRules = `
    CRITICAL VISUAL RULES:
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles, NO EMOJIS.
    3. The image must look like a professional RAW PHOTO or RENDER.

    !!! SCALE AND COMPOSITION LOCK (STRICT MANDATORY) !!!:
    1. FRAMING: Every image MUST be a "Medium Shot". The character must occupy exactly 3/4 of the vertical frame height.
    2. PRODUCT SCALE: The product "${productName}" MUST maintain a fixed, realistic size relative to the character. 
    3. CONSISTENCY: The product MUST NOT shrink or grow between scenes.
    4. NO DISTORTION: The product is a solid, non-deformable object. Its geometric proportions must match the PRODUCT_REFERENCE image 1:1.
  `;

  const backgroundRule = backgroundReferencePart 
    ? `ENVIRONMENT PERSPECTIVE (CRITICAL): 
       1. Use the EXACT same environment and background elements from the BACKGROUND_REFERENCE image.
       2. RE-ORIENT the camera view of this environment based on the specified angle: "${cameraAngle || 'front view'}".
       3. The background must look like the same physical room/space, but seen from a different point of view matching the subject.`
    : `ENVIRONMENT: Set the scene in a natural ${backgroundNote || 'daily lifestyle setting'}. The environment's perspective must match the camera angle: "${cameraAngle || 'front view'}".`;

  const angleInstruction = cameraAngle 
    ? `CAMERA PERSPECTIVE (MANDATORY): Capture the entire scene (subject, product, and room architecture) from the technical angle: "${cameraAngle}". Ensure all lines of perspective in the background converge correctly for this angle.`
    : `CAMERA PERSPECTIVE: Randomly choose a professional, dynamic camera angle (e.g., front, 45 degree).`;

  const poseInstruction = poseLabel ? `CHARACTER POSE (MANDATORY): The person is ${poseLabel}. Ensure the character's interaction with the product and the fit of their OUTFIT matches this pose naturally.` : "";

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${skinRealismRule}
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${poseInstruction} 
    ${angleInstruction}
    SCENE CONTEXT: "${scriptPart}". 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });

  if (!isNoProductRequested) {
    referenceImageParts.forEach(part => contents.push({ inlineData: part }));
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageData?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - Nhân vật đang cầm trên tay sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết để tạo video AI (VEO-3) dài 8 giây cho video KOC Review.
  PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.
  !!! CRITICAL FIDELITY RULE !!!: Maintain 100% face, hair, and OUTFIT consistency with the provided reference images. The character must wear the EXACT same clothes as shown in the starting frame.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO (BẮT BUỘC NHẤT QUÁN). Mô tả nhân vật, trang phục và khuôn mặt y hệt ảnh tham chiếu.
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Không gian đồng nhất với bối cảnh ảnh tham chiếu.
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16). Chuyển động slow vào nhân vật hoặc sản phẩm. tuyệt đối không thay đổi bối cảnh, nhân vật và trang phục trong suốt 8s.
  PHẦN 5: LỜI THOẠI (DÙNG CHO ĐỒNG BỘ): ✨ Model speaks in ${voiceDetail} characteristics (${voiceGender}): "${scriptText}". Khớp môi 1 cách hoàn hảo.
  PHẦN 6: CHẤT LƯỢNG KỸ THUẬT: 4K, 60fps, Không có nhạc nền, Không hiệu ứng chuyển cảnh.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageData) {
    contents.push({ inlineData: { mimeType: 'image/png', data: productImageData.split(',')[1] || productImageData } });
  }
  if (generatedImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    console.error("Video prompt generation error", error);
    return "Error generating video prompt.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import ErrorBoundary from './components/ErrorBoundary';
import KocReviewModule from './modules/KocReviewModule';
import Shopee8sModule from './modules/Shopee8sModule';
import CoverLinkModule from './modules/CoverLinkModule';
import CarouselModule from './modules/CarouselModule';
import VideoPovModule from './modules/VideoPovModule';
import Review1kModule from './modules/Review1kModule';
import PersonificationModule from './modules/PersonificationModule';
import Personification2Module from './modules/Personification2Module';
import Fashion16sModule from './modules/Fashion16sModule';
import VuaTvModule from './modules/VuaTvModule';
import DhbcModule from './modules/DhbcModule';
import { getStoredKeys, saveStoredKeys } from './services/keyService';
import { VALID_USERS } from './types';

type ModuleTab = 'koc' | 'shopee8s' | 'review1k' | 'videopov' | 'carousel' | 'fashion16s' | 'personification' | 'personification2' | 'coverlink' | 'dhbc' | 'vuatv';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('koc_studio_auth') === 'true';
  });
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [currentTab, setCurrentTab] = useState<ModuleTab>('koc');
  const [showKeyModal, setShowKeyModal] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [tempKeys, setTempKeys] = useState(getStoredKeys().join('\n'));

  // States for Import process
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mobileMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleExportReady = (e: any) => {
      const { data, moduleName } = e.detail;
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `${moduleName}_export_${new Date().getTime()}.json`;
      link.click();
      URL.revokeObjectURL(url);
    };

    const handleImportProgress = (e: any) => {
      const { percent, complete } = e.detail;
      setImportProgress(percent);
      if (complete) {
        setTimeout(() => {
          setIsImporting(false);
          setImportProgress(0);
        }, 500);
      }
    };

    const handleClickOutside = (event: MouseEvent) => {
      if (mobileMenuRef.current && !mobileMenuRef.current.contains(event.target as Node)) {
        setIsMobileMenuOpen(false);
      }
    };

    window.addEventListener('EXPORT_DATA_READY', handleExportReady);
    window.addEventListener('IMPORT_DATA_PROGRESS', handleImportProgress);
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
      window.removeEventListener('EXPORT_DATA_READY', handleExportReady);
      window.removeEventListener('IMPORT_DATA_PROGRESS', handleImportProgress);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const triggerExport = () => {
    window.dispatchEvent(new CustomEvent('REQUEST_EXPORT_DATA'));
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const jsonData = JSON.parse(event.target?.result as string);
        setIsImporting(true);
        setImportProgress(0);
        window.dispatchEvent(new CustomEvent('REQUEST_IMPORT_DATA', { detail: jsonData }));
      } catch (err) {
        alert("File JSON không đúng định dạng!");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = VALID_USERS.find(u => u.u === username && u.p === password);
    if (user) {
      setIsAuthenticated(true);
      sessionStorage.setItem('koc_studio_auth', 'true');
    } else {
      alert('Tên đăng nhập hoặc mật khẩu không chính xác!');
    }
  };

  const saveKeys = () => {
    saveStoredKeys(tempKeys);
    setShowKeyModal(false);
    alert('Đã cập nhật danh sách API Key!');
  };

  const renderActiveModule = () => {
    switch(currentTab) {
      case 'koc': return <KocReviewModule />;
      case 'shopee8s': return <Shopee8sModule />;
      case 'review1k': return <Review1kModule />;
      case 'videopov': return <VideoPovModule />;
      case 'carousel': return <CarouselModule />;
      case 'fashion16s': return <Fashion16sModule />;
      case 'personification': return <PersonificationModule />;
      case 'personification2': return <Personification2Module />;
      case 'coverlink': return <CoverLinkModule />;
      case 'dhbc': return <DhbcModule />;
      case 'vuatv': return <VuaTvModule />;
      default: return <KocReviewModule />;
    }
  };

  const tabs: { id: ModuleTab; label: string }[] = [
    { id: 'koc', label: 'KOC Review' },
    { id: 'shopee8s', label: 'Shopee Video' },
    { id: 'videopov', label: 'Video POV' },
    { id: 'carousel', label: 'Ảnh Cuộn' },
    { id: 'fashion16s', label: 'Fashion' },
    { id: 'personification', label: 'Nhân Hóa' },
    { id: 'personification2', label: 'Nhân Hóa (BETA)' },
    { id: 'coverlink', label: 'Cover Link' },
    { id: 'dhbc', label: 'ĐHBC' },
    { id: 'vuatv', label: 'VTV' },
  ];

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-start justify-center p-6 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-80 h-80 bg-orange-600/10 rounded-full blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-80 h-80 bg-blue-600/5 rounded-full blur-[120px] animate-pulse delay-700"></div>
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 !mt-[50px] shadow-2xl relative z-10 border border-slate-200 transform transition-all">
          <div className="flex flex-col items-center mb-10">
            <div className="relative w-20 h-16 flex items-center justify-center mb-6">
                <div className="absolute left-0 top-1 w-12 h-12 bg-[#EE4D2D] rounded-2xl flex items-center justify-center shadow-lg transform -rotate-12 border border-orange-400/20">
                    <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="currentColor"><path d="M19 6h-2c0-2.76-2.24-5-5-5S7 3.24 7 6H5c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2zm-7-3c1.66 0 3 1.34 3 3H9c0-1.66-1.34-3-3-3zm7 17H5V8h14v12zm-7-8c-1.66 0-3-1.34-3-3H9c0 1.66 1.34 3 3 3s3-1.34 3-3h-2c0 1.66-1.34-3-3 3z"/></svg>
                </div>
                <div className="absolute left-6 top-0 w-12 h-12 bg-black rounded-2xl flex items-center justify-center shadow-xl border border-slate-700 transform rotate-12 z-10">
                    <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="currentColor"><path d="M12.53.02C13.84 0 15.14.01 16.44 0c.08 1.53.63 3.09 1.75 4.17 1.12 1.11 2.7 1.62 4.24 1.79v4.03c-1.44-.05-2.89-.35-4.2-.97-.57-.26-1.1-.59-1.59-1.01V14c0 1.39-.24 2.77-.92 4-1.14 2.1-3.41 3.52-5.76 3.75-2.29.23-4.73-.61-6.22-2.39-1.48-1.78-1.89-4.38-1.04-6.52.85-2.14 2.92-3.71 5.21-3.95v4c-.81.14-1.61.64-2 1.38-.4.75-.41 1.7-.1 2.47.33.82 1.05 1.48 1.93 1.66 1.01.21 2.15-.12 2.8-.93.38-.47.56-1.07.56-1.67V.02z"/></svg>
                </div>
            </div>
            <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tighter leading-none">KOC <span className="text-orange-600">STUDIO</span></h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em] mt-1">AI Creative Engine</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Tên đăng nhập</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg></span>
                <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Nhập tên người dùng..." className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-4 focus:ring-orange-50 focus:border-orange-500 transition-all placeholder:text-slate-300" required autoFocus />
              </div>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Mật khẩu</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg></span>
                <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Nhập mật khẩu..." className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-4 focus:ring-orange-50 focus:border-orange-500 transition-all placeholder:text-slate-300" required />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 hover:scale-[1.02] active:scale-95 transition-all text-sm uppercase tracking-widest mt-4">ĐĂNG NHẬP</button>
          </form>
          <div className="mt-10 text-center"><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-relaxed">Security Gate Powered by<br/> KÔNG VĂN STUDIO</p></div>
        </div>
      </div>
    );
  }

  return (
    <ErrorBoundary>
      <div className="min-h-screen bg-slate-50 flex flex-col relative font-['Inter']">
        <nav className="bg-white border-b border-slate-100 sticky top-0 z-[100] shadow-sm">
          <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
              {/* Unified Menu Button (Mobile & Desktop) */}
              <div className="relative" ref={mobileMenuRef}>
                  <button 
                    onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                    className="flex items-center gap-3 px-4 py-2 border border-[#e2e8f0] rounded-2xl bg-white hover:bg-slate-50 transition-all group"
                  >
                    <svg className="w-5 h-5 text-slate-700" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 6h16M4 12h16M4 18h16" />
                    </svg>
                    <span className="text-[#334155] font-black text-xs uppercase tracking-tight">MENU DANH MỤC</span>
                  </button>

                  {/* Unified Dropdown Menu */}
                  {isMobileMenuOpen && (
                    <div className="absolute left-0 mt-3 w-64 bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden z-[110] animate-fadeIn">
                      <div className="p-2 flex flex-col gap-1">
                        {tabs.map((t) => (
                          <button 
                            key={t.id} 
                            onClick={() => {
                              setCurrentTab(t.id);
                              setIsMobileMenuOpen(false);
                            }} 
                            className={`w-full text-left px-4 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight transition-all ${currentTab === t.id ? 'bg-orange-600 text-white shadow-md' : 'text-slate-600 hover:bg-slate-50'}`}
                          >
                            {t.label}
                          </button>
                        ))}
                        <div className="h-px bg-slate-100 my-1"></div>
                        <button 
                          onClick={() => { setShowKeyModal(true); setIsMobileMenuOpen(false); }}
                          className="w-full text-left px-4 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight text-slate-400 hover:bg-slate-50 hover:text-orange-600 flex items-center gap-2"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1.01.293-.707l5.964-5.964A6 6 0 1121 9z" /></svg>
                          CẤU HÌNH API KEY
                        </button>
                      </div>
                    </div>
                  )}
              </div>

              {/* Right Side Controls */}
              <div className="flex items-center gap-5">
                {/* Export Data Icon */}
                <button 
                  onClick={triggerExport} 
                  className="text-slate-300 hover:text-orange-600 transition-colors"
                  title="Xuất File JSON"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 15l5-5-5-5M4 18c0-4.418 3.582-8 8-8h8" />
                  </svg>
                </button>

                {/* Logout Icon */}
                <button 
                  onClick={() => { sessionStorage.removeItem('koc_studio_auth'); window.location.reload(); }} 
                  className="text-slate-300 hover:text-red-600 transition-colors"
                  title="Đăng xuất"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                  </svg>
                </button>
              </div>
          </div>
        </nav>

        {/* Global Action Boxed Panel */}
        <div className="max-w-7xl mx-auto w-full px-4 pt-4">
          <div className="bg-white rounded-2xl border border-slate-200 py-3 px-6 shadow-sm flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-slate-400 border border-slate-100">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
              </div>
              <div className="leading-tight">
                <h4 className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Nạp Dữ liệu</h4>
                <p className="text-[9px] text-slate-300 font-bold uppercase tracking-tighter">Import JSON Project</p>
              </div>
            </div>

            <div className="flex gap-2 w-full sm:w-auto">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-slate-100 text-slate-600 text-[9px] font-black rounded-xl hover:bg-slate-200 transition-all active:scale-95 uppercase tracking-widest border border-slate-200"
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
                Tải Dự Án (Import)
              </button>
              <input type="file" ref={fileInputRef} onChange={handleFileSelect} className="hidden" accept="application/json" />
            </div>
          </div>
        </div>

        <main className="flex-1 pb-32">
          {renderActiveModule()}
        </main>

        <footer className="bg-white border-t border-slate-200 py-3 fixed bottom-0 left-0 right-0 z-[60]">
          <div className="max-w-7xl mx-auto px-4 flex items-center justify-center">
            <div className="text-[#64748b] font-bold text-[12px] tracking-tight uppercase">@COPYRIGHT KÔNG VĂN - 0923.200.820</div>
          </div>
        </footer>

        {/* Import Progress Overlay */}
        {isImporting && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/80 backdrop-blur-md">
            <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-sm w-full text-center border border-slate-100 animate-fadeIn">
              <div className="w-20 h-20 bg-orange-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <svg className="w-10 h-10 text-orange-500 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
              </div>
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter mb-2">Đang nạp dữ liệu...</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-8 italic">Phân tích & Phân phối thông minh</p>
              <div className="relative h-4 bg-slate-100 rounded-full overflow-hidden mb-4 border border-slate-200">
                <div className="absolute top-0 left-0 h-full bg-orange-500 transition-all duration-300 ease-out shadow-[0_0_15px_rgba(249,115,22,0.3)]" style={{ width: `${importProgress}%` }} />
              </div>
              <span className="text-3xl font-black text-orange-600 tabular-nums">{importProgress}%</span>
            </div>
          </div>
        )}

        {/* API Key Manager Modal */}
        {showKeyModal && (
          <div className="fixed inset-0 z-[100] flex items-start justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowKeyModal(false)}></div>
            <div className="relative bg-white w-full max-w-lg rounded-[2rem] p-8 !mt-[50px] shadow-2xl border border-slate-200 animate-fadeIn">
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">QUẢN LÝ API KEY</h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Xoay vòng tự động để tránh giới hạn</p>
                </div>
                <button onClick={() => setShowKeyModal(false)} className="p-2 text-slate-300 hover:text-slate-500 transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>
              <div className="space-y-4">
                <div className="bg-orange-50 border border-orange-100 p-4 rounded-2xl flex gap-3">
                  <svg className="w-5 h-5 text-orange-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  <p className="text-[11px] text-orange-700 leading-relaxed font-medium">Nhập mỗi API Key trên 1 dòng. Hệ thống sẽ sử dụng tuần tự các Key này cho mỗi lượt tạo ảnh để tối ưu tốc độ và quota.</p>
                </div>
                <textarea value={tempKeys} onChange={(e) => setTempKeys(e.target.value)} placeholder="Paste danh sách API Key tại đây..." className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-mono focus:ring-4 focus:ring-orange-50 outline-none resize-none" />
                <div className="flex gap-3">
                  <button onClick={() => setShowKeyModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">HỦY BỔ</button>
                  <button onClick={saveKeys} className="flex-1 py-4 bg-orange-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest shadow-lg shadow-orange-100 hover:bg-orange-700 active:scale-95 transition-all">LƯU DANH SÁCH</button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </ErrorBoundary>
  );
};

export default App;
